searchData={"items":[{"type":"module","title":"HookSniff","doc":"Official Elixir client for the HookSniff webhook delivery service.","ref":"HookSniff.html"},{"type":"module","title":"Usage - HookSniff","doc":"client = HookSniff.new(\"hr_live_...\")\n\n    # Create endpoint\n    {:ok, endpoint} = HookSniff.Endpoints.create(client, %{url: \"https://myapp.com/webhook\"})\n\n    # Send webhook\n    {:ok, delivery} = HookSniff.Webhooks.send(client, %{\n      endpoint_id: endpoint[\"id\"],\n      event: \"order.created\",\n      data: %{order_id: \"12345\"}\n    })","ref":"HookSniff.html#module-usage"},{"type":"type","title":"HookSniff.t/0","doc":"","ref":"HookSniff.html#t:t/0"},{"type":"function","title":"HookSniff.new/2","doc":"Create a new HookSniff client.","ref":"HookSniff.html#new/2"},{"type":"module","title":"HookSniff.Endpoints","doc":"Endpoints resource — CRUD operations for webhook endpoints.","ref":"HookSniff.Endpoints.html"},{"type":"function","title":"HookSniff.Endpoints.create/2","doc":"Create a new endpoint.","ref":"HookSniff.Endpoints.html#create/2"},{"type":"function","title":"HookSniff.Endpoints.delete/2","doc":"Delete an endpoint.","ref":"HookSniff.Endpoints.html#delete/2"},{"type":"function","title":"HookSniff.Endpoints.get/2","doc":"Get an endpoint by ID.","ref":"HookSniff.Endpoints.html#get/2"},{"type":"function","title":"HookSniff.Endpoints.list/2","doc":"List all endpoints.","ref":"HookSniff.Endpoints.html#list/2"},{"type":"function","title":"HookSniff.Endpoints.rotate_secret/2","doc":"Rotate the signing secret for an endpoint.","ref":"HookSniff.Endpoints.html#rotate_secret/2"},{"type":"module","title":"HookSniff.WebhookVerification","doc":"Webhook signature verification for HookSniff.\n\nSupports both simple HMAC-SHA256 verification and Standard Webhooks\n(Svix-compatible) verification with timestamp tolerance.\n\nAlso supports Svix headers (svix-id, svix-signature, svix-timestamp) as fallback.","ref":"HookSniff.WebhookVerification.html"},{"type":"module","title":"Example - HookSniff.WebhookVerification","doc":"# Verify from request headers\n    result = HookSniff.WebhookVerification.verify_webhook_from_headers(\n      payload: body,\n      headers: conn.req_headers |> Map.new(),\n      secret: \"whsec_...\"\n    )\n\n    case result do\n      {:ok, payload} -> # Valid webhook\n      {:error, reason} -> # Invalid\n    end","ref":"HookSniff.WebhookVerification.html#module-example"},{"type":"function","title":"HookSniff.WebhookVerification.verify_signature/3","doc":"Verify a webhook signature using HMAC-SHA256 (legacy format).","ref":"HookSniff.WebhookVerification.html#verify_signature/3"},{"type":"function","title":"HookSniff.WebhookVerification.verify_webhook/1","doc":"Verify a webhook using Standard Webhooks headers (Svix-compatible).\n\nReturns `{:ok, parsed_payload}` or `{:error, reason}`.","ref":"HookSniff.WebhookVerification.html#verify_webhook/1"},{"type":"function","title":"HookSniff.WebhookVerification.verify_webhook_from_headers/1","doc":"Verify a webhook from headers with automatic header detection.\n\nSupports both Standard Webhooks headers (webhook-id, webhook-signature, webhook-timestamp)\nand Svix headers (svix-id, svix-signature, svix-timestamp) as fallback.","ref":"HookSniff.WebhookVerification.html#verify_webhook_from_headers/1"},{"type":"module","title":"HookSniff.Webhooks","doc":"Webhooks resource — send, list, replay, batch, and inspect webhooks.","ref":"HookSniff.Webhooks.html"},{"type":"function","title":"HookSniff.Webhooks.attempts/2","doc":"Get delivery attempts.","ref":"HookSniff.Webhooks.html#attempts/2"},{"type":"function","title":"HookSniff.Webhooks.batch/2","doc":"Send multiple webhooks in a batch.","ref":"HookSniff.Webhooks.html#batch/2"},{"type":"function","title":"HookSniff.Webhooks.export/2","doc":"Export deliveries.","ref":"HookSniff.Webhooks.html#export/2"},{"type":"function","title":"HookSniff.Webhooks.get/2","doc":"Get a delivery by ID.","ref":"HookSniff.Webhooks.html#get/2"},{"type":"function","title":"HookSniff.Webhooks.list/2","doc":"List deliveries with optional filters.","ref":"HookSniff.Webhooks.html#list/2"},{"type":"function","title":"HookSniff.Webhooks.replay/2","doc":"Replay a delivery.","ref":"HookSniff.Webhooks.html#replay/2"},{"type":"function","title":"HookSniff.Webhooks.search/2","doc":"Search deliveries with filters.","ref":"HookSniff.Webhooks.html#search/2"},{"type":"function","title":"Options - HookSniff.Webhooks.search/2","doc":"- `:q` - Search query\n  - `:event` - Event type filter\n  - `:status` - Status filter\n  - `:endpoint_id` - Endpoint ID filter\n  - `:page` - Page number (default: 1)\n  - `:per_page` - Results per page (default: 20)","ref":"HookSniff.Webhooks.html#search/2-options"},{"type":"function","title":"HookSniff.Webhooks.send/2","doc":"Send a webhook.","ref":"HookSniff.Webhooks.html#send/2"},{"type":"exception","title":"HookSniff.Error","doc":"","ref":"HookSniff.Error.html"},{"type":"type","title":"HookSniff.Error.t/0","doc":"","ref":"HookSniff.Error.html#t:t/0"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.2"}}